export const meta = {
  id: 4, sem: 1,
  title: 'Articles & Determiners',
  desc: 'Using a, an, the and other determiners correctly'
}

export const notes = `
<div class="notes-card">
    <h3>1. What Are Determiners?</h3>
    <p>A <strong>determiner</strong> comes before a noun to specify <em>which one</em> or <em>how many</em>. Every noun phrase needs a determiner or no article (zero article).</p>
    <div class="example">
      <strong>Articles:</strong> a, an, the<br>
      <strong>Demonstratives:</strong> this, that, these, those<br>
      <strong>Possessives:</strong> my, your, his, her, its, our, their<br>
      <strong>Quantifiers:</strong> some, any, many, much, few, little, several, all, both, enough<br>
      <strong>Numbers:</strong> one, two, three … / first, second, third …<br>
      <strong>Distributives:</strong> each, every, either, neither
    </div>
    <p>Only <em>one</em> determiner typically precedes a noun: ✗ "my the book" → ✓ "my book" or "the book".</p>
  </div>

  <div class="notes-card">
    <h3>2. Indefinite Articles: A and AN</h3>
    <p>Use <strong>a</strong> or <strong>an</strong> before <em>singular countable nouns</em> when referring to any one thing (not a specific one).</p>
    <div class="example">
      <strong>First mention:</strong> "I saw a dog." (not yet known to the listener)<br>
      <strong>One of many:</strong> "She is a teacher." (one among many teachers)<br>
      <strong>Jobs / roles:</strong> "He wants to be an engineer."
    </div>
    <p>The choice between <strong>a</strong> and <strong>an</strong> depends on the <em>sound</em>, not the letter:</p>
    <div class="formula">A = before a CONSONANT sound: a book, a cat, a university (yoo-), a European (yoo-), a one-way street (won-)</div>
    <div class="formula">AN = before a VOWEL sound: an apple, an hour (silent h), an honest man, an MBA (em-), an X-ray (ex-)</div>
    <div class="example">
      ✓ "a uniform" (yoo- sound) &nbsp;|&nbsp; ✓ "an umbrella" (uh- sound)<br>
      ✓ "a hotel" (h sound) &nbsp;|&nbsp; ✓ "an honour" (silent h = oh- sound)<br>
      ✓ "a useful tool" (yoo- sound) &nbsp;|&nbsp; ✓ "an unusual event" (uh- sound)
    </div>
    <p><strong>Never use a/an with:</strong> plural nouns ("✗ a books") or uncountable nouns ("✗ a water").</p>
  </div>

  <div class="notes-card">
    <h3>3. The Definite Article: THE</h3>
    <p>Use <strong>the</strong> when both the speaker and listener know <em>which specific one</em> is meant.</p>
    <div class="example">
      <strong>Second mention:</strong> "I saw a dog. The dog was barking."<br>
      <strong>Unique things:</strong> the sun, the moon, the earth, the sky, the equator, the Internet<br>
      <strong>Superlatives:</strong> the best, the largest, the most beautiful<br>
      <strong>Ordinals:</strong> the first, the second, the third<br>
      <strong>Specific groups:</strong> the rich, the poor, the elderly, the blind, the French, the Japanese<br>
      <strong>Geographical:</strong> the Amazon, the Pacific Ocean, the Alps, the Philippines, the UAE, the UK
    </div>
    <div class="formula">Instruments (playing): "She plays the piano." / "He plays the guitar."</div>
    <p><strong>NO "the" before:</strong> names (John), most countries (Singapore), cities (London), continents (Asia), languages (English), school subjects (mathematics), meals (breakfast), sports (football), days/months (Monday, January).</p>
  </div>

  <div class="notes-card">
    <h3>4. Zero Article (No Article)</h3>
    <p>Use <strong>no article</strong> (zero article) in these situations:</p>
    <div class="example">
      <strong>Plural nouns — general statements:</strong> "Dogs are loyal." / "Cats are independent."<br>
      <strong>Uncountable nouns — general:</strong> "Water is essential." / "Love is blind." / "Honesty is the best policy."<br>
      <strong>Names of people, countries, cities, continents:</strong> Singapore, Asia, London, Maria<br>
      <strong>Languages and school subjects:</strong> English, Malay, mathematics, science, art<br>
      <strong>Sports and games:</strong> football, basketball, chess, badminton<br>
      <strong>Meals:</strong> breakfast, lunch, dinner, supper<br>
      <strong>Days and months:</strong> Monday, Friday, January, December
    </div>
    <div class="formula">Institutions (meaning/purpose): "at school", "at university", "at work", "at home", "at church", "in hospital", "in prison"</div>
    <div class="formula">Transport (by + vehicle): "by car", "by bus", "by train", "by plane", "by bicycle"</div>
    <div class="formula">Time expressions: "at night", "at noon", "at midnight"</div>
  </div>

  <div class="notes-card">
    <h3>5. Demonstrative Determiners</h3>
    <p><strong>This, that, these, those</strong> point to specific nouns. They must agree in number with the noun.</p>
    <div class="example">
      <strong>This</strong> (near, singular): "This book is interesting." / "This week is busy."<br>
      <strong>That</strong> (far, singular): "That building is tall." / "That day was memorable."<br>
      <strong>These</strong> (near, plural): "These apples are fresh." / "These students work hard."<br>
      <strong>Those</strong> (far, plural): "Those shoes are expensive." / "Those were difficult times."
    </div>
    <div class="formula">Singular noun → this / that &nbsp;&nbsp; Plural noun → these / those</div>
    <div class="example">
      ✗ "this one books" → ✓ "these books" (plural noun needs plural demonstrative)<br>
      ✗ "those student" → ✓ "those students" or "that student"
    </div>
    <p>Demonstratives can also be used for <strong>time</strong>: "this year / next year", "that day / those days", "these days" (= nowadays).</p>
  </div>

  <div class="notes-card">
    <h3>6. Quantifiers</h3>
    <p>Quantifiers express <em>how many</em> or <em>how much</em>. Choose based on whether the noun is countable or uncountable.</p>
    <div class="formula">Countable plural ONLY: many, few, a few, several, both, a number of, a great many, a large number of</div>
    <div class="formula">Uncountable ONLY: much, little, a little, a great deal of, a large amount of</div>
    <div class="formula">Both countable &amp; uncountable: some, any, a lot of / lots of, enough, plenty of, most, all, no</div>
    <div class="example">
      <strong>some vs any:</strong><br>
      • some = positive statements + polite requests: "I have some milk." / "Can I have some water?"<br>
      • any = questions + negatives + conditionals: "Is there any milk?" / "I don't have any time."<br><br>
      <strong>few vs a few (countable):</strong><br>
      • few = almost none (negative/pessimistic meaning): "Few students passed." (most failed)<br>
      • a few = a small number (positive/optimistic meaning): "A few students passed." (some succeeded)<br><br>
      <strong>little vs a little (uncountable):</strong><br>
      • little = almost none: "There is little hope." (nearly hopeless)<br>
      • a little = some: "There is a little hope." (some hope exists)
    </div>
    <p><strong>much/many</strong> are mainly used in questions and negatives: "I don't have much time." / "Are there many people?"</p>
  </div>

  <div class="notes-card">
    <h3>7. Common Article Errors + Quick Reference</h3>
    <p>These errors are common in Singapore English. Learn to spot and correct them.</p>
    <div class="example">
      ✗ "She is teacher." → ✓ "She is <strong>a</strong> teacher." (singular countable needs a/an)<br>
      ✗ "I play the football." → ✓ "I play <strong>football</strong>." (no article with sports)<br>
      ✗ "He is a honest man." → ✓ "He is <strong>an</strong> honest man." (silent h = vowel sound)<br>
      ✗ "The life is beautiful." → ✓ "<strong>Life</strong> is beautiful." (general uncountable = zero article)<br>
      ✗ "I go to the school by the bus." → ✓ "I go to <strong>school</strong> by <strong>bus</strong>." (institution + transport)<br>
      ✗ "She plays piano." → ✓ "She plays <strong>the</strong> piano." (musical instruments need the)
    </div>
    <div class="formula">A / AN → singular countable, first mention or non-specific (sound rule: a = consonant, an = vowel)</div>
    <div class="formula">THE → specific, both parties know which one; unique things; second mention; superlatives; instruments; geographical groups</div>
    <div class="formula">ZERO → plural/uncountable general; names; places; languages; subjects; sports; meals; by + transport; at + institution</div>
  </div>
`

